  "std:test": "// `std:test` v1 — a pure-VL assertion library over the intrinsic floor\n// (docs/std-design.md D5). The matcher surface reads jest-shaped through\n// STRUCT-RECEIVER UFCS: `expectI32(x).toEqual(y)` builds a small `Expectation`\n// struct and `.toEqual` is a free `self`-function resolved by self+arity. A\n// failed assertion calls `__trap__()` (std-design D1 item 5 / OD2) — a\n// process-fatal abort, jest's \"a test stops at its first failed expectation\".\n// A passing assertion is a no-op. The runner half (`vl test`, per-test trap\n// isolation, reporting — docs/test-runner-design.md) drives these from the\n// host; under bare `vl run` a green file exits 0, a red one aborts.\n//\n// SCOPE OF v1 — concrete value types, no generic `expect<T>`. The\n// design-doc shape `expect(v: i32 | i64 | f64 | boolean | string)` returning\n// `Expectation { actual: <that union> }` is NOT expressible on the current\n// native seed: a value-union STRUCT FIELD does not round-trip — reading it\n// back (`self.actual`) mis-types the load (the field is a `ref`, the read is\n// emitted as `i32`), and a struct carrying a union field is rejected as\n// not-equatable. Generic `expect<T>` is independently blocked (exporting\n// generics is out of phase-1 scope, std-design \"generic exports\" / slice 2).\n// So v1 stores the value in CONCRETE fields under a tag and splays the entry\n// point per type (`expectI32`/`expectBool`/`expectStr`). i64 and f64 are\n// absent because the seed restricts struct fields to i32/boolean/string/array\n// (\"only i32 / boolean / string / array struct fields are supported\"); they\n// return once wide/float fields land. The names stay jest-compatible for the\n// generic `expect` upgrade (std-design slice 6).\n//\n// One `Expectation` shape, one method name each: the seed does not overload by\n// receiver type (two `toEqual`s with different `self` structs fail UFCS\n// resolution), and a struct-union receiver (`self: ExpectI32 | ExpectStr`)\n// crashes the emitter — so a single tagged struct carries every value kind.\ntype Expectation = {\n  tag: i32,        // 1 = i32, 2 = boolean, 3 = string — selects the live field\n  i: i32,\n  b: boolean,\n  s: string,\n  negated: boolean // `.not()` flips the pass/fail sense (jest's `.not`)\n}\n\n// `expect` over an i32 value: the receiver for the integer matchers.\nexport function expectI32(value: i32): Expectation {\n  return { tag: 1, i: value, b: false, s: \"\", negated: false }\n}\n\n// `expect` over a boolean value: the receiver for `toBeTrue`/`toBeFalse` and\n// boolean `toEqual`.\nexport function expectBool(value: boolean): Expectation {\n  return { tag: 2, i: 0, b: value, s: \"\", negated: false }\n}\n\n// `expect` over a string value.\nexport function expectStr(value: string): Expectation {\n  return { tag: 3, i: 0, b: false, s: value, negated: false }\n}\n\n// Inverts the pass/fail sense: `expectI32(5).not().toEqual(6)` passes because\n// 5 != 6. Returns a fresh `Expectation` (the receiver is a value; no aliasing).\nexport function not(self: Expectation): Expectation {\n  return { tag: self.tag, i: self.i, b: self.b, s: self.s, negated: !self.negated }\n}\n\n// Does the boxed value structurally equal `expected`? The `expected` UFCS\n// argument is a value union — narrowed by `is` so each arm compares the live\n// CONCRETE field directly. (Comparing through the union by boxing the field is\n// avoided: boxing a boolean field into the union mis-tags it as i32 on the\n// current seed, silently failing the compare; the narrow-then-concrete path\n// sidesteps that.) A type mismatch (`expectI32(4).toEqual(\"4\")`) is unequal.\nfunction matches(self: Expectation, expected: i32 | boolean | string): boolean {\n  if self.tag == 1 {\n    if expected is i32 { return self.i == expected }\n    return false\n  }\n  if self.tag == 2 {\n    if expected is boolean { return self.b == expected }\n    return false\n  }\n  if expected is string { return self.s == expected }\n  return false\n}\n\n// Aborts unless `matches` agrees with the current sense (`negated`). Factored\n// so every matcher shares one pass/fail/`__trap__` decision.\nfunction adjudicate(self: Expectation, ok: boolean) {\n  if self.negated {\n    if ok { __trap__() }\n  } else {\n    if !ok { __trap__() }\n  }\n}\n\n// `.toEqual` — structural equality, jest semantics (std-design D5/OD6).\n// `.toBe` (referential identity) is reserved for the future `===` (ROADMAP\n// A15) and is deliberately NOT part of v1.\nexport function toEqual(self: Expectation, expected: i32 | boolean | string) {\n  adjudicate(self, matches(self, expected))\n}\n\n// `.toBeTrue` — the receiver is a boolean and holds `true`. A non-boolean\n// receiver is never true.\nexport function toBeTrue(self: Expectation) {\n  adjudicate(self, self.tag == 2 && self.b)\n}\n\n// `.toBeFalse` — the receiver is a boolean and holds `false`.\nexport function toBeFalse(self: Expectation) {\n  adjudicate(self, self.tag == 2 && !self.b)\n}\n",
